# Example task: Write a config package that loads server settings from environment variables with sensible defaults (Addr defaults to :8080, read timeout, max page size), parses durations and integers, validates the result and returns an error for invalid values.
```go
package config

import (
	"fmt"
	"os"
	"strconv"
	"time"
)

// Config holds server settings loaded from the environment with sane defaults.
type Config struct {
	Addr        string
	ReadTimeout time.Duration
	MaxPageSize int
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

// Load reads configuration from environment variables, applying defaults for
// any that are unset, then validates the result.
func Load() (Config, error) {
	c := Config{
		Addr:        getenv("ADDR", ":8080"),
		ReadTimeout: 5 * time.Second,
		MaxPageSize: 100,
	}
	if s := os.Getenv("READ_TIMEOUT"); s != "" {
		d, err := time.ParseDuration(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid READ_TIMEOUT: %w", err)
		}
		c.ReadTimeout = d
	}
	if s := os.Getenv("MAX_PAGE_SIZE"); s != "" {
		n, err := strconv.Atoi(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid MAX_PAGE_SIZE: %w", err)
		}
		c.MaxPageSize = n
	}
	if err := c.Validate(); err != nil {
		return Config{}, err
	}
	return c, nil
}

// Validate reports whether the configuration is usable.
func (c Config) Validate() error {
	if c.Addr == "" {
		return fmt.Errorf("addr must not be empty")
	}
	if c.MaxPageSize <= 0 {
		return fmt.Errorf("max page size must be positive, got %d", c.MaxPageSize)
	}
	return nil
}
```
# Example task: Write a package main bearer-token auth middleware (standard library only): Auth(token string) returning func(http.Handler) http.Handler that rejects requests without a valid `Authorization: Bearer <token>` header with 401 (constant-time compare) and passes valid requests to the wrapped next handler. Compose it as Auth(token)(mux).
```go
// Package main shows the standard bearer-token auth middleware shape: a
// constructor returning func(http.Handler) http.Handler so it composes with
// any mux, and a constant-time token compare.
package main

import (
	"crypto/subtle"
	"net/http"
)

// Auth returns middleware enforcing `Authorization: Bearer <token>` on every
// request. Constructed once with the expected token, it WRAPS the next
// handler — callers compose it as Auth(token)(mux), they never invoke the
// middleware with (w, r) directly:
//
//	protected := Auth("secret")(mux)
func Auth(token string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			got, ok := bearerToken(r)
			if !ok || subtle.ConstantTimeCompare([]byte(got), []byte(token)) != 1 {
				http.Error(w, "unauthorized", http.StatusUnauthorized)
				return
			}
			next.ServeHTTP(w, r)
		})
	}
}

func bearerToken(r *http.Request) (string, bool) {
	const prefix = "Bearer "
	h := r.Header.Get("Authorization")
	if len(h) <= len(prefix) || h[:len(prefix)] != prefix {
		return "", false
	}
	return h[len(prefix):], true
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})
	_ = Auth("secret")(mux) // wire into an http.Server in a real backend
}
```

