# Example task: Write a package main CRUD JSON router (standard library only) on http.ServeMux with Go 1.22 METHOD+pattern routes (POST /items, GET /items, GET /items/{id} via r.PathValue): NewRouter(token) wraps ONLY the mutating POST route in bearer-token auth middleware (register the wrapped http.Handler with mux.Handle, bare handler funcs with mux.HandleFunc), 201 echoes the created entity as JSON, a duplicate ID is 409 Conflict via errors.Is(err, ErrExists), a malformed body is 400, GET list returns a JSON array, a missing id is 404.
```go
// Package main is a full CRUD JSON router on http.ServeMux with Go 1.22
// METHOD+pattern routes, auth on MUTATING routes only, and correct status
// mapping: 201 echoes the created entity as JSON, duplicate IDs are 409,
// malformed bodies 400, list is a JSON ARRAY, missing IDs 404.
package main

import (
	"encoding/json"
	"errors"
	"net/http"
	"sort"
	"sync"
)

var ErrExists = errors.New("already exists")

type Item struct {
	ID   string `json:"id"`
	Name string `json:"name"`
}

type memStore struct {
	mu    sync.RWMutex
	items map[string]Item
}

func (s *memStore) create(it Item) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, dup := s.items[it.ID]; dup {
		return ErrExists
	}
	s.items[it.ID] = it
	return nil
}

func (s *memStore) list() []Item {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Item, 0, len(s.items))
	for _, it := range s.items {
		out = append(out, it)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

func (s *memStore) get(id string) (Item, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	it, ok := s.items[id]
	return it, ok
}

// NewRouter registers method+pattern routes; ONLY the mutating route is
// wrapped in auth (GET stays open), so tests of GET need no token while
// tests of POST always send one.
func NewRouter(token string) http.Handler {
	s := &memStore{items: make(map[string]Item)}
	mux := http.NewServeMux()
	// wrapped handler is an http.Handler -> register with mux.Handle
	mux.Handle("POST /items", authWrap(token, http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var it Item
		if err := json.NewDecoder(r.Body).Decode(&it); err != nil || it.ID == "" {
			http.Error(w, "bad request", http.StatusBadRequest)
			return
		}
		if err := s.create(it); err != nil {
			if errors.Is(err, ErrExists) {
				http.Error(w, "conflict", http.StatusConflict) // duplicate -> 409
				return
			}
			http.Error(w, "internal", http.StatusInternalServerError)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusCreated)
		_ = json.NewEncoder(w).Encode(it) // echo the created entity
	})))
	mux.HandleFunc("GET /items", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(s.list()) // a JSON ARRAY of items
	})
	mux.HandleFunc("GET /items/{id}", func(w http.ResponseWriter, r *http.Request) {
		it, ok := s.get(r.PathValue("id"))
		if !ok {
			http.Error(w, "not found", http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(it)
	})
	return mux
}

func authWrap(token string, next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Header.Get("Authorization") != "Bearer "+token {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func main() {
	_ = NewRouter("secret")
}
```

